Interactive Explorer
Use these selectors to focus on one experiment, one plate, or specific wells.

dashboard = await FileAttachment("output/clam/dashboard-data.csv").csv({typed: true})

cleanDashboard = dashboard.filter(d =&gt;
  d.experiment_dir != null &&
  d.plate_id != null &&
  d.well_id != null &&
  d.well_id !== "" &&
  Number.isFinite(d.time_hr) &&
  Number.isFinite(d.value)
)

experimentValues = [...new Set(cleanDashboard.map(d =&gt; d.experiment_dir))]

experimentSortKey = (name) =&gt; {
  const m = /^([0-9]{8})/.exec(name)
  if (!m) return Number.NEGATIVE_INFINITY
  return Number.parseInt(m[1], 10)
}

mostRecentExperiment = experimentValues
  .slice()
  .sort((a, b) =&gt; {
    const ka = experimentSortKey(a)
    const kb = experimentSortKey(b)
    if (ka !== kb) return kb - ka
    return a.localeCompare(b)
  })[0]

experiments = ["All", ...experimentValues]
viewof experimentSel = Inputs.select(experiments, {
  label: "Experiment",
  value: mostRecentExperiment || "All"
})

activeExperimentSel = experiments.includes(experimentSel) ? experimentSel : (mostRecentExperiment || "All")

plateCandidates = cleanDashboard
  .filter(d =&gt; activeExperimentSel === "All" || d.experiment_dir === activeExperimentSel)
plates = ["All", ...new Set(plateCandidates.map(d =&gt; d.plate_id))]
defaultPlateSel = "All"
viewof plateSel = Inputs.select(plates, {
  label: "Plate",
  value: defaultPlateSel
})

activePlateSel = plates.includes(plateSel) ? plateSel : "All"

selectionRows = cleanDashboard
  .filter(d =&gt; (activeExperimentSel === "All" || d.experiment_dir === activeExperimentSel) &&
               (activePlateSel === "All" || d.plate_id === activePlateSel))

wells = [...new Set(selectionRows.map(d =&gt; d.well_id))].sort()
wellsWithAll = ["All", ...wells]

viewof wellSel = Inputs.select(wellsWithAll, {
  label: "Well(s)",
  multiple: true,
  value: ["All"]
})

rawWellSel = Array.isArray(wellSel) ? wellSel : [wellSel]
validWellSel = rawWellSel.filter(w =&gt; wellsWithAll.includes(w))
allWellsSelected = validWellSel.length === 0 || validWellSel.includes("All")
selectedWells = allWellsSelected
  ? wells
  : validWellSel.filter(w =&gt; w !== "All")

nonEmptyString = v =&gt; v != null && `${v}`.trim() !== ""
invalidGroupTokens = new Set(["NA", "N/A", "NULL", "NAN", "&lt;NA&gt;"])
validGroupValue = v =&gt; {
  if (!nonEmptyString(v)) return false
  const norm = `${v}`.trim().toUpperCase()
  return !invalidGroupTokens.has(norm)
}

groupColumns = cleanDashboard.length &gt; 0
  ? Object.keys(cleanDashboard[0]).filter(k =&gt; /_group$/.test(k) && cleanDashboard.some(d =&gt; validGroupValue(d[k])))
  : []

noneGroupOption = "None (plot by well)"

viewof groupColSel = Inputs.select(
  [noneGroupOption, ...groupColumns],
  {
    label: "Group column",
    value: noneGroupOption
  }
)

activeGroupCol = groupColumns.includes(groupColSel) ? groupColSel : null

naturalCompare = (a, b) =&gt; `${a}`.localeCompare(`${b}`, undefined, {
  numeric: true,
  sensitivity: "base"
})

groupValues = activeGroupCol === null
  ? []
  : [...new Set(selectionRows.map(d =&gt; `${d[activeGroupCol]}`.trim()).filter(validGroupValue))].sort(naturalCompare)

viewof groupValSel = Inputs.select(
  ["All", ...groupValues],
  {
    label: "Group value",
    value: "All"
  }
)

viewof aggregationSel = Inputs.radio(["Mean", "Individual replicates"], {
  label: "Group display",
  value: "Mean",
  disabled: activeGroupCol === null
})

activeGroupVal = groupValues.includes(groupValSel) ? groupValSel : "All"

measurementColumns = cleanDashboard.length &gt; 0
  ? Object.keys(cleanDashboard[0]).filter(
      k =&gt; /_measur(?:e)?ment$/.test(k) && cleanDashboard.some(d =&gt; Number.isFinite(d[k]))
    )
  : []

viewof measurementColSel = Inputs.select(
  measurementColumns.length &gt; 0 ? measurementColumns : ["(none available)"],
  {
    label: "Measurement column",
    value: measurementColumns.length &gt; 0 ? measurementColumns[0] : "(none available)"
  }
)

activeMeasurementCol = measurementColumns.includes(measurementColSel) ? measurementColSel : null

viewModes = ["Raw fluorescence", "Delta fluorescence", "Normalized fluorescence", "Measurement-normalized fluorescence"]
viewof dataViewSel = Inputs.select(viewModes, {
  label: "Data view",
  value: "Raw fluorescence"
})

viewof errorBarSel = Inputs.select(["Hide error bars", "Show error bars"], {
  label: "Error bars",
  value: "Hide error bars"
})

viewof plotStyleSel = Inputs.select(["Line plot", "Box plot"], {
  label: "Plot style",
  value: "Line plot"
})

filtered = selectionRows.filter(d =&gt;
  (allWellsSelected || selectedWells.includes(d.well_id)) &&
  (activeGroupCol === null || validGroupValue(d[activeGroupCol])) &&
  (activeGroupCol === null || activeGroupVal === "All" || `${d[activeGroupCol]}` === `${activeGroupVal}`)
)

groupingMessage = activeGroupCol === null
  ? "Grouping: Well (no group column selected)"
  : `Grouping: ${activeGroupCol}`

allPlateMessage = activePlateSel === "All"
  ? "Plate = All: data include wells from multiple plates. Select a specific plate for one trajectory per well."
  : null

plotSubtitle = allPlateMessage === null
  ? groupingMessage
  : `${groupingMessage}\n${allPlateMessage}`

yField = dataViewSel === "Normalized fluorescence"
      ? "normalized_value"
  : (dataViewSel === "Measurement-normalized fluorescence" ? "measurement_normalized_value" : "value")
metricField = dataViewSel === "Delta fluorescence" ? "value" : yField
plotYField = "plot_y"

yLabel = dataViewSel === "Delta fluorescence"
  ? "Delta fluorescence (current - previous timepoint)"
  : (dataViewSel === "Normalized fluorescence"
      ? "Normalized fluorescence (value / mean blank at same plate and time)"
      : (dataViewSel === "Measurement-normalized fluorescence"
          ? `Fluorescence normalized by ${activeMeasurementCol || "selected measurement"}`
          : "Fluorescence"))

isBlank = d =&gt; d.is_blank === true || d.is_blank === "TRUE" || d.is_blank === 1 || d.is_blank === "1"
groupMode = activeGroupCol !== null
groupValue = d =&gt; `${d[activeGroupCol]}`.trim()
seriesLabel = groupMode ? `Group (${activeGroupCol})` : "Well"
sampleTraceKey = d =&gt; nonEmptyString(d.sample_id_group)
  ? `${d.sample_id_group}`.trim()
  : `${d.well_id}`.trim()

seriesKey = d =&gt; {
  const rawGroupVal = activeGroupCol === null ? "All" : d[activeGroupCol]
  const groupVal = nonEmptyString(rawGroupVal) ? `${rawGroupVal}`.trim() : "NA"
  if (groupVal.toUpperCase() === "BLANK") return "Blank"

  if (aggregationSel === "Individual replicates" && activeGroupCol !== null) {
    return `${groupVal}: ${sampleTraceKey(d)}`
  }
  return groupVal
}

traceKey = d =&gt; groupMode
  ? `${d.experiment_dir}|${d.plate_id}|${seriesKey(d)}`
  : `${d.experiment_dir}|${d.plate_id}|${d.well_id}`

measurementReady = dataViewSel !== "Measurement-normalized fluorescence" || activeMeasurementCol !== null

plottedBase = dataViewSel === "Measurement-normalized fluorescence"
  ? filtered.map(d =&gt; {
      const denom = activeMeasurementCol === null ? NaN : d[activeMeasurementCol]
      const valid = Number.isFinite(d.value) && Number.isFinite(denom) && denom !== 0
      return {
        ...d,
        measurement_normalized_value: valid ? d.value / denom : NaN
      }
    })
  : filtered

plotted = plottedBase.filter(d =&gt; Number.isFinite(d[metricField]))

traceKeyEffective = d =&gt; activePlateSel === "All"
  ? `${d.experiment_dir}|${seriesKey(d)}`
  : traceKey(d)

plottedEffective = (() =&gt; {
  const groups = new Map()
  const showIndiv = aggregationSel === "Individual replicates" && activeGroupCol !== null

  for (const d of plotted) {
    const sampleKey = sampleTraceKey(d)
    const traceId = showIndiv
      ? (activePlateSel === "All"
        ? `${d.experiment_dir}|${sampleKey}`
        : `${d.experiment_dir}|${d.plate_id}|${sampleKey}`)
      : traceKeyEffective(d)

    const key = `${traceId}|${d.time_hr}`

    if (!groups.has(key)) {
      groups.set(key, {
        ...d,
        trace_id: traceId,
        well_ids: [d.well_id],
        values: [d[metricField]]
      })
    } else {
      const g = groups.get(key)
      g.values.push(d[metricField])
      if (!g.well_ids.includes(d.well_id)) g.well_ids.push(d.well_id)
    }
  }

  return [...groups.values()].map(g =&gt; {
    const sId = seriesKey(g)
    return {
      ...g,
      series_id: sId,
      rep_count: g.values.length,
      [metricField]: d3.mean(g.values),
      well_id: g.well_ids.join(", "),
      metric_se: g.values.length &gt; 1 ? d3.deviation(g.values) / Math.sqrt(g.values.length) : NaN
    }
  })
})()

sortedEffective = plottedEffective
  .slice()
  .sort((a, b) =&gt;
    a.trace_id.localeCompare(b.trace_id) ||
    (a.time_hr - b.time_hr)
  )

plottedSorted = dataViewSel === "Delta fluorescence"
  ? (() =&gt; {
      const prevByTrace = new Map()
      return sortedEffective.map(d =&gt; {
        const tkey = d.trace_id
        const prev = prevByTrace.get(tkey)
        const cur = d[metricField]
        const delta = prev && Number.isFinite(prev.mean) ? (cur - prev.mean) : 0
        const curSe = d.metric_se
        const deltaSe = prev && Number.isFinite(curSe) && Number.isFinite(prev.se)
          ? Math.sqrt((curSe * curSe) + (prev.se * prev.se))
          : NaN
        prevByTrace.set(tkey, {mean: cur, se: curSe})
        return {
          ...d,
          [plotYField]: delta,
          plot_se: deltaSe
        }
      })
    })()
  : sortedEffective.map(d =&gt; ({
      ...d,
      [plotYField]: d[metricField],
      plot_se: d.metric_se
    }))

errorBarData = plottedSorted.filter(d =&gt;
  d.rep_count &gt; 1 &&
  Number.isFinite(d[plotYField]) &&
  Number.isFinite(d.plot_se) &&
  d.plot_se &gt; 0
)

showErrorBars = errorBarSel === "Show error bars" && errorBarData.length &gt; 0
boxPlotMode = plotStyleSel === "Box plot"

hashString = s =&gt; {
  let hash = 0
  for (const ch of `${s}`) {
    hash = Math.imul(31, hash) + ch.charCodeAt(0) | 0
  }
  return hash &gt;&gt;&gt; 0
}

numericTimes = [...new Set(plottedSorted.map(d =&gt; d.time_hr))]
  .filter(Number.isFinite)
  .sort((a, b) =&gt; a - b)

timeValues = numericTimes.map(String)

timeSpacing = numericTimes.length &gt; 1
  ? Math.min(...numericTimes.slice(1).map((t, i) =&gt; t - numericTimes[i]).filter(d =&gt; d &gt; 0))
  : 1

boxValueField = dataViewSel === "Delta fluorescence" ? "box_delta_value" : metricField

boxPlotData = dataViewSel === "Delta fluorescence"
  ? (() =&gt; {
      const prevByWell = new Map()
      const sortedRaw = plottedBase
        .filter(d =&gt; Number.isFinite(d.value))
        .slice()
        .sort((a, b) =&gt;
          a.experiment_dir.localeCompare(b.experiment_dir) ||
          a.plate_id.localeCompare(b.plate_id) ||
          a.well_id.localeCompare(b.well_id) ||
          a.time_hr - b.time_hr
        )

      return sortedRaw.map(d =&gt; {
        const key = `${d.experiment_dir}|${d.plate_id}|${d.well_id}`
        const prev = prevByWell.get(key)
        const deltaValue = prev && Number.isFinite(prev.value) ? (d.value - prev.value) : NaN

        prevByWell.set(key, {value: d.value})

        const result = {
          ...d,
          series_id: seriesKey(d)
        }
        result[boxValueField] = deltaValue

        return result
      }).filter(d =&gt; Number.isFinite(d[boxValueField]))
    })()
  : plottedBase
      .filter(d =&gt; Number.isFinite(d[metricField]))
      .map(d =&gt; ({
        ...d,
        series_id: seriesKey(d),
        [boxValueField]: d[metricField]
      }))

presentSeries = [...new Set(plottedSorted.map(d =&gt; String(d.series_id)))]
nonBlankKeys = presentSeries.filter(k =&gt; k !== "Blank").sort(naturalCompare)
hasBlankSeries = presentSeries.includes("Blank")
colorDomain = hasBlankSeries ? ["Blank", ...nonBlankKeys] : nonBlankKeys

boxPresentSeries = [...new Set(boxPlotData.map(d =&gt; d.series_id))]
boxNonBlankKeys = boxPresentSeries.filter(k =&gt; k !== "Blank").sort(naturalCompare)
boxHasBlankSeries = boxPresentSeries.includes("Blank")
boxSeriesOrder = boxHasBlankSeries ?
["Blank", ...boxNonBlankKeys] : boxNonBlankKeys

groupedSpan = Math.max(0.14, Math.min(0.9, (Number.isFinite(timeSpacing) ? timeSpacing : 1) * 0.85))
groupStep = boxSeriesOrder.length &gt; 1 ? groupedSpan / (boxSeriesOrder.length - 1) : 0
seriesOffset = new Map(
  boxSeriesOrder.map((key, idx) =&gt; [key, (idx - (boxSeriesOrder.length - 1) / 2) * groupStep])
)

groupOffset = d =&gt; seriesOffset.get(d.series_id ?? seriesKey(d)) ?? 0

jitterRadius = boxSeriesOrder.length &gt; 1
  ? Math.max(0.01, groupStep * 0.32)
  : Math.max(0.03, (Number.isFinite(timeSpacing) ? timeSpacing : 1) * 0.06)

jitterOffset = d =&gt; {
  const seed = `${d.trace_id}|${d.series_id}|${d.time_hr}|${d.well_id}`
  const value = hashString(seed) / 4294967295
  return (value - 0.5) * jitterRadius * 2
}

tableau = d3.schemeTableau10
nonBlankColors = nonBlankKeys.map((_, i) =&gt; tableau[i % tableau.length])
colorRange = hasBlankSeries
  ? ["#000000", ...nonBlankColors.slice(0, nonBlankKeys.length)]
  : nonBlankColors.slice(0, nonBlankKeys.length)

tooltipTitle = d =&gt; {
  const parts = [
    `Experiment: ${d.experiment_dir}`,
    `Sample: ${d.sample_id_group}`,
    `Wells: ${d.well_id}`,
    `Time: ${d.time_hr}h`,
    `${metricField}: ${d[metricField]?.toFixed(2)}`
  ]

  if (activeGroupCol) {
    parts.unshift(`${activeGroupCol}: ${d[activeGroupCol]}`)
  }

  if (d.rep_count &gt; 1) {
    parts.push(`Wells averaged: ${d.rep_count}`)
  }

  return parts.join("\n")
}

normalizedUnavailable = dataViewSel === "Normalized fluorescence" && plottedSorted.length === 0
measurementUnavailable = dataViewSel === "Measurement-normalized fluorescence" && (!measurementReady || plottedSorted.length === 0)
groupUnavailable = activeGroupCol !== null && filtered.length === 0

groupUnavailable
  ? `No data available for ${activeGroupCol} under the current selection. Choose a different Group column/value or adjust Experiment, Plate, and Well filters.`
  : normalizedUnavailable
  ? "Normalized fluorescence unavailable for this selection. Add a layout.txt with blank wells marked (is_blank = TRUE), then rebuild dashboard data."
  : measurementUnavailable
    ? "Measurement-normalized fluorescence unavailable for this selection. Ensure a non-zero numeric value exists in the selected *.measurement (or *.measurment) column for these wells."
  : (() =&gt; {
      const plotWrap = document.createElement("div")
      const subtitleWrap = document.createElement("div")
      subtitleWrap.style.marginBottom = "0.35rem"
      subtitleWrap.style.color = "#374151"
      subtitleWrap.style.fontSize = "0.95rem"
      subtitleWrap.style.lineHeight = "1.35"
      subtitleWrap.style.fontWeight = "600"

      const groupingLine = document.createElement("div")
      groupingLine.textContent = groupingMessage
      subtitleWrap.appendChild(groupingLine)

      if (allPlateMessage !== null) {
        const plateLine = document.createElement("div")
        plateLine.textContent = allPlateMessage
        plateLine.style.fontWeight = "400"
        subtitleWrap.appendChild(plateLine)
      }

      plotWrap.appendChild(subtitleWrap)
      plotWrap.innerHTML = ""
      plotWrap.appendChild(subtitleWrap)
      if (boxPlotMode) {
        plotWrap.appendChild(Plot.plot({
          height: 420,
          style: {
            color: "#111827",
            background: "#ffffff"
          },
          fx: {
            label: "Time (hours)",
            domain: timeValues,
            padding: 0.1
          },
          x: {
            type: "band",
            domain: boxSeriesOrder,
            axis: null
          },
          y: {
            label: yLabel,
            grid: true,
            zero: true,
            nice: true
          },
          color: {
            legend: true,
            label: seriesLabel,
            domain: colorDomain,
            range: colorRange
          },
          marks: [
            Plot.boxY(boxPlotData, {
              fx: d =&gt; `${d.time_hr}`,
              x: "series_id",
              y: boxValueField,
              fill: "series_id",
              fillOpacity: 0.4,
              stroke: "series_id",
              strokeWidth: 1.5
            }),
            Plot.dot(boxPlotData, {
              fx: d =&gt; `${d.time_hr}`,
              x: "series_id",
              y: boxValueField,
              fill: "series_id",
              r: 3,
              opacity: 0.7,
              stroke: "#ffffff",
              strokeWidth: 0.5,
              title: tooltipTitle,
              tip: true
            })
          ]
        }))
      } else {
        plotWrap.appendChild(Plot.plot({
          height: 420,
          style: {
            color: "#111827",
            background: "#ffffff"
          },
          x: {label: "Time (hours)", tickValues: timeValues},
          y: {label: yLabel},
          color: {
            legend: true,
            label: seriesLabel,
            domain: colorDomain,
            range: colorRange
          },
          marks: [
            Plot.gridX({stroke: "#d1d5db", strokeOpacity: 1}),
            Plot.gridY({stroke: "#d1d5db", strokeOpacity: 1}),
            ...(showErrorBars
              ? [Plot.ruleX(errorBarData, {
                  x: "time_hr",
                  y1: d =&gt; d[plotYField] - d.plot_se,
                  y2: d =&gt; d[plotYField] + d.plot_se,
                  stroke: seriesKey,
                  strokeOpacity: 0.6,
                  strokeWidth: 1.2
                })]
              : []),
            Plot.line(plottedSorted, {
              x: "time_hr",
              y: plotYField,
              stroke: "series_id",
              z: "trace_id",
              strokeWidth: aggregationSel === "Individual replicates" ? 1.2 : 2.2,
              strokeOpacity: aggregationSel === "Individual replicates" ? 0.6 : 1.0,
              curve: "linear"
            }),
            Plot.dot(plottedSorted, {
              x: "time_hr",
              y: plotYField,
              fill: "series_id",
              r: 2.5,
              title: tooltipTitle,
              tip: true
            })
          ]
        }))
      }
      return plotWrap
    })()

Landing page for quick info on where we are with implementing easy resazurin metabolism assays for oysters. Please explore the Github Repo, glimpse real-time activity in from the lab here, and dive deeper with the Canonical Protocol.






📖 New: Manuscript



Huffmyer AS, N Ozguner, M Baird, C Elvrum, C Kounellas, D Dicksion, SJ White, L Plough, MR Gavery, N Krebs, W Walton, J Small, M Pitsenbarger, H Ealy-Whitfield, S Roberts. From blue to pink: Resazurin as a high-throughput proxy for metabolic rate in oysters. In review. PeerJ. Available on bioRxiv at http://doi.org/10.1101/2025.11.06.686367.




Clam Dashboard
Explore auto-updated clam plate-reader time-series at the Clam Dashboard. The dashboard rebuilds from files in data/clam and supports whole-plate and individual well views over time.


Summary
This protocol uses a resazurin-based assay to measure individual metabolic responses to elevated temperature stress over a 4-5-hour period. Resazurin is a redox-sensitive dye that fluoresces as it is reduced by cellular respiration, providing a proxy for metabolic activity. Individuals are incubated in a resazurin working solution at a high temperature (e.g., ~42°C), and metabolic activity is monitored through fluorescence measurements taken at hourly intervals. Fluorescence measurements are conducted using an excitation wavelength of 530 nm (e.g., a 528/20 nm bandpass filter) and an emission wavelength of 590 nm (e.g., a 590/20 nm bandpass filter) using a fluorescence plate reader.



Resorufin is highly fluorescent (excitation ~570 nm, emission ~585 nm). The amount of resorufin produced is directly proportional to the metabolic activity of the cells.




Highlights to date
• Metabolic rate is a reliable predictor of short-term stress resilience — oysters that suppress metabolic activity under stress tend to survive better than those with heightened activity in laboratory tests.
• Rapid assessment is possible — metabolism can be measured rapidly at at high replication, within hours using the resazurin assay, eliminating the need for long-term trials or multiple days of traditional respiration measurements.
• Genetic background drives metabolic performance — consistent family-level and line-level differences demonstrate that stress-tolerant metabolic traits are heritable.
• Assay is scalable across life stages and conditions — works effectively from tiny spat (~7 mm) to adult oysters, across temperature and salinity stressors.
• Parental and ploidy effects matter — offspring stress resistance is affected by parental histry, and diploid vs triploid oysters show distinct metabolic signatures.
• High sensitivity measurements — fluorescence measurements provide highly sensitive measurements of oyster metabolism.


Video Demo





Preparing solutions
To prepare the resazurin assay solutions, first make a stock by combining resazurin salt with water and a small amount of DMSO. Store this stock in a dark refrigerator or freezer. The working solution consists primarily of seawater (about 98.5%), with small proportions of resazurin stock (0.2%), DMSO (0.1%), and an antibiotic/antifungal solution (1%). Adjust the total volume based on the number and size of organisms being tested, ensuring animals are fully submerged. Trials are typically scaled for small (≤7 mm), medium (15–40 mm), or large (&gt;40 mm) seed using appropriately sized containers. See our widget below to calculate the solutions required! See our Canonical Protocol for further details.

Solutions required

Stock resazurin solution 

To make the resazurin stock solution (10 mL) mix the following. We will use this solution for multiple trials. 

0.5 g resazurin salt
10 mL DI water
10 µL DMSO

Store in a dark fridge or freezer. 

Working resazurin solution

First, determine the volume of resazurin required depending on the size of your organism and the container size. Here are some examples that we have used before. We recommend performing preliminary trials to ensure that a change in resazurin fluorescence can be detected over the time scale desired. This protocol was developed to detect a change in resazurin fluorescence within 5 hours in small seed (&lt;7mm) and larger seed (10-30mm). 

Small seed (&lt;7mm length): trials conducted in 96 well plates (300uL volume in each well)
Medium seed (15-40 mm length): trials conducted in small plastic cups (20 mL volume) or 12, 24, or 48-well plates
Large seed/adults (&gt;40 mm length): trials can be conducted in tripour cups, beakers, or plastic cups. Scale volume appropriately. The animals should be fully submerged. 

Use the calculator below to calculate the formula for your working solution.
The working solution requires the following: 

Filtered seawater (DI water with Instant Ocean adjusted to 23-25 ppt or filtered (&lt;1um) seawater) 
Resazurin stock solution as made above in step 1 
DMSO
Antibiotic solution 100x Penn/Strep & 100x Fungizone - this should be kept frozen in a dark freezer and thawed before use (thaw in the dark or cover with aluminum foil)




Interactive Recipe Calculator
Use this calculator to automatically determine the required amounts of each ingredient based on your experimental setup.

viewof plateType = Inputs.select(
  [
    "96-well plate (35 mL per plate)",
    "48-well plate (25 mL per plate)", 
    "24-well plate (15 mL per plate)",
    "12-well plate (10 mL per plate)",
    "Custom volume"
  ],
  {
    label: "Plate type:",
    value: "96-well plate (35 mL per plate)"
  }
)

viewof numPlates = Inputs.range([1, 80], {
  label: "Number of plates:",
  value: 1,
  step: 1
})

viewof customVolume = Inputs.range([1, 2000], {
  label: "Custom total volume (mL):",
  value: 35,
  step: 1,
  disabled: plateType !== "Custom volume"
})

viewof extraPercent = Inputs.range([0, 20], {
  label: "Extra volume for safety (%):",
  value: 10,
  step: 5
})

// Calculations
plateVolumes = new Map([
  ["96-well plate (35 mL per plate)", 35],
  ["48-well plate (25 mL per plate)", 25],
  ["24-well plate (15 mL per plate)", 15], 
  ["12-well plate (10 mL per plate)", 10],
  ["Custom volume", customVolume]
])

baseVolume = plateVolumes.get(plateType) * numPlates
totalVolume = baseVolume * (1 + extraPercent / 100)

seawaterVolume = totalVolume * 0.98666
resazurinVolume = totalVolume * 0.00222
dmsoVolume = totalVolume * 0.001
antibioticVolume = totalVolume * 0.01

// Helper function to format volumes appropriately
function formatVolume(volume) {
  if (volume &gt;= 1) {
    return volume.toFixed(2) + " mL";
  } else {
    return (volume * 1000).toFixed(0) + " µL";
  }
}

